// Generated by GitHub Copilot
import { useEffect, useMemo, useState } from "react";

import { ScoreCard } from "./components/ScoreCard";
import {
    fetchRuns,
    runBenchmark,
    type BenchmarkPayload,
    type BenchmarkRunDetail,
    type BenchmarkRunSummary,
} from "./lib/api";

const DEFAULT_PAYLOAD: BenchmarkPayload = {
    name: "baseline-faiss-gpt4o-mini",
    retriever: "faiss",
    generator: "gpt-4o-mini",
    k: 5,
    cases: [
        {
            question: "What uptime is promised?",
            reference_answer: "The SLA target is 99.9% uptime.",
            retrieved_ids: ["doc-1", "doc-3", "doc-4"],
            relevant_ids: ["doc-1"],
            generated_answer: "The SLA target is 99.9% uptime.",
            retrieval_latency_ms: 18,
            generation_latency_ms: 420,
        },
        {
            question: "How should incidents be escalated?",
            reference_answer: "Escalate through tier 1, tier 2, then incident commander.",
            retrieved_ids: ["doc-9", "doc-2", "doc-15"],
            relevant_ids: ["doc-2"],
            generated_answer: "Escalate from tier 1 to tier 2 then the incident commander.",
            retrieval_latency_ms: 30,
            generation_latency_ms: 510,
        },
    ],
};

// Generated by GitHub Copilot
/** Render benchmark execution dashboard with run form and historical leaderboard table. */
export default function App(): JSX.Element {
    const [payloadInput, setPayloadInput] = useState(JSON.stringify(DEFAULT_PAYLOAD, null, 2));
    const [latestRun, setLatestRun] = useState<BenchmarkRunDetail | null>(null);
    const [runs, setRuns] = useState<BenchmarkRunSummary[]>([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        void refreshRuns();
    }, []);

    // Generated by GitHub Copilot
    /** Load benchmark run history from API with user-visible error state. */
    async function refreshRuns(): Promise<void> {
        try {
            const history = await fetchRuns();
            setRuns(history);
        } catch (apiError) {
            setError(apiError instanceof Error ? apiError.message : "Unable to load benchmark runs");
        }
    }

    // Generated by GitHub Copilot
    /** Parse JSON payload and execute benchmark run against backend API. */
    async function onRunBenchmark(): Promise<void> {
        setLoading(true);
        setError(null);

        try {
            const parsedPayload = JSON.parse(payloadInput) as BenchmarkPayload;
            const run = await runBenchmark(parsedPayload);
            setLatestRun(run);
            await refreshRuns();
        } catch (apiError) {
            setError(apiError instanceof Error ? apiError.message : "Benchmark execution failed");
        } finally {
            setLoading(false);
        }
    }

    const metrics = useMemo(() => {
        if (!latestRun) {
            return [];
        }

        return [
            {
                label: "MRR",
                value: latestRun.mrr.toFixed(3),
                hint: "Higher is better",
            },
            {
                label: "Recall@k",
                value: latestRun.recall_at_k.toFixed(3),
                hint: `k = ${latestRun.k}`,
            },
            {
                label: "Judge Score",
                value: latestRun.avg_judge_score.toFixed(3),
                hint: "Lexical overlap baseline",
            },
            {
                label: "Avg Latency",
                value: `${latestRun.avg_latency_ms.toFixed(1)} ms`,
                hint: "Retrieval + generation",
            },
            {
                label: "P95 Latency",
                value: `${latestRun.p95_latency_ms.toFixed(1)} ms`,
            },
        ];
    }, [latestRun]);

    return (
        <main className="page">
            <header className="hero" aria-labelledby="page-title">
                <h1 id="page-title">ragbench</h1>
                <p>Benchmark RAG pipelines with measurable retrieval and answer quality metrics.</p>
            </header>

            <section className="panel" aria-labelledby="run-config-title">
                <h2 id="run-config-title">Run Configuration</h2>
                <p className="subtle">Edit payload JSON and execute a benchmark run.</p>
                <label htmlFor="payload-input" className="sr-only">
                    Benchmark payload JSON
                </label>
                <textarea
                    id="payload-input"
                    value={payloadInput}
                    onChange={(event) => setPayloadInput(event.target.value)}
                    rows={16}
                    spellCheck={false}
                />
                <div className="actions">
                    <button type="button" onClick={() => void onRunBenchmark()} disabled={loading}>
                        {loading ? "Running..." : "Run Benchmark"}
                    </button>
                </div>
                {error ? (
                    <p className="error" role="alert">
                        {error}
                    </p>
                ) : null}
            </section>

            <section className="panel" aria-labelledby="latest-summary-title">
                <h2 id="latest-summary-title">Latest Summary</h2>
                {!latestRun ? <p className="subtle">Run a benchmark to see summary metrics.</p> : null}
                <div className="score-grid">
                    {metrics.map((metric) => (
                        <ScoreCard key={metric.label} label={metric.label} value={metric.value} hint={metric.hint} />
                    ))}
                </div>
            </section>

            <section className="panel" aria-labelledby="leaderboard-title">
                <h2 id="leaderboard-title">Run History</h2>
                <div className="table-wrap">
                    <table>
                        <thead>
                            <tr>
                                <th>Name</th>
                                <th>Retriever</th>
                                <th>Generator</th>
                                <th>Cases</th>
                                <th>MRR</th>
                                <th>Recall@k</th>
                                <th>Judge</th>
                                <th>P95 Latency</th>
                            </tr>
                        </thead>
                        <tbody>
                            {runs.map((run) => (
                                <tr key={run.run_id}>
                                    <td>{run.name}</td>
                                    <td>{run.retriever}</td>
                                    <td>{run.generator}</td>
                                    <td>{run.case_count}</td>
                                    <td>{run.mrr.toFixed(3)}</td>
                                    <td>{run.recall_at_k.toFixed(3)}</td>
                                    <td>{run.avg_judge_score.toFixed(3)}</td>
                                    <td>{run.p95_latency_ms.toFixed(1)} ms</td>
                                </tr>
                            ))}
                            {runs.length === 0 ? (
                                <tr>
                                    <td colSpan={8} className="subtle">
                                        No runs yet.
                                    </td>
                                </tr>
                            ) : null}
                        </tbody>
                    </table>
                </div>
            </section>
        </main>
    );
}
